INSERT INTO products (name, slug, short_description, description, image_url, gallery_images, category_id, brand_id, status, is_new, is_featured, rating, review_count, specifications) VALUES
('Glaco 45km/h Cristalizador de Vidros Soft99 75ml', 'glaco-45kmh-soft99-75ml',
'Cristalizador de vidros que repelir a água. Em deslocamentos acima de 45km/h dispensa o limpador.',
'GLACO é um cristalizador de vidros desenvolvido para repelir a água que se acumula sobre para-brisas automotivos em dias chuvosos. A tecnologia contida nos produtos da linha Glaco garantem a formação de uma película protetora nos vidros que impede que as gotas de chuva "grudem" na superfície. Em deslocamentos acima de 45km/h o efeito do Glaco se mostra eficiente, proporcionando ótima visibilidade. Protege o vidro contra agentes externos como fezes de pássaros, poluição e óleos. Rendimento: até 18 para-brisas. Durabilidade: até 2 meses.',
'https://images.tcdn.com.br/img/img_prod/1152560/glaco_45km_h_cristalizador_de_vidros_repelente_de_chuva_soft99_04132_75ml_211_1_c60e62047d943b1eb1798e4e6b2c757f.jpg',
'["https://images.tcdn.com.br/img/img_prod/1152560/glaco_45km_h_cristalizador_de_vidros_repelente_de_chuva_soft99_04132_75ml_211_1_c60e62047d943b1eb1798e4e6b2c757f.jpg","https://images.tcdn.com.br/img/img_prod/1152560/glaco_45km_h_cristalizador_de_vidros_repelente_de_chuva_soft99_04132_75ml_211_2_ab00cb772207f4dc29e94df956a9fc71.jpg","https://images.tcdn.com.br/img/img_prod/1152560/cristalizador_de_vidros_glaco_soft99_75ml_211_3_c89e0c5dbe35d4b88366750159c98e0e.jpg"]',
'70c01ac7-0184-4d49-9e17-8887cfd4cf7c', 'e992f177-70fb-4f9e-8188-455de352d018', 'published', false, true, 5.0, 4,
